# Custom policy: require resource groups to match naming pattern {app}-{env}-*
# Policy rule JSON:
cat > rg-naming-policy.json << 'EOF'
{
  "if": {
    "allOf": [
      { "field": "type", "equals": "Microsoft.Resources/subscriptions/resourceGroups" },
      { "not": { "field": "name", "match": "*-dev-*" } },
      { "not": { "field": "name", "match": "*-staging-*" } },
      { "not": { "field": "name", "match": "*-prod-*" } },
      { "not": { "field": "name", "like": "platform-*" } }
    ]
  },
  "then": { "effect": "deny" }
}
EOF

az policy definition create \
  --name require-rg-naming-convention \
  --display-name 'Require resource group naming convention' \
  --rules rg-naming-policy.json \
  --mode All

az policy assignment create \
  --name require-rg-naming \
  --policy require-rg-naming-convention \
  --scope /subscriptions/{subscriptionId}

// compute.bicep — deploying into myapp-prod-compute
// but referencing VNet from myapp-prod-networking

param computeRG string = 'myapp-prod-compute'
param networkingRG string = 'myapp-prod-networking'
param vnetName string = 'myapp-vnet'
param subnetName string = 'compute-subnet'

// Reference existing resource in another resource group
resource vnet 'Microsoft.Network/virtualNetworks@2023-09-01' existing = {
  name: vnetName
  scope: resourceGroup(networkingRG)  // cross-group reference
}

// Use the subnet from the referenced VNet
resource nic 'Microsoft.Network/networkInterfaces@2023-09-01' = {
  name: 'myVM-nic'
  location: resourceGroup().location
  properties: {
    ipConfigurations: [
      {
        name: 'ipconfig1'
        properties: {
          subnet: {
            id: '${vnet.id}/subnets/${subnetName}'
          }
        }
      }
    ]
  }
}

// main.bicep — subscription scope, orchestrates multiple RG deployments
targetScope = 'subscription'

param location string = 'eastus'
param app string = 'myapp'
param env string = 'prod'

resource networkingRG 'Microsoft.Resources/resourceGroups@2021-04-01' existing = {
  name: '${app}-${env}-networking'
}
resource computeRG 'Microsoft.Resources/resourceGroups@2021-04-01' existing = {
  name: '${app}-${env}-compute'
}

// Deploy VNet into networking group
module vnet './modules/vnet.bicep' = {
  name: 'deploy-vnet'
  scope: networkingRG
  params: { location: location, vnetName: '${app}-vnet' }
}

// Deploy VM into compute group, referencing the VNet
module vm './modules/vm.bicep' = {
  name: 'deploy-vm'
  scope: computeRG
  dependsOn: [vnet]
  params: {
    location: location
    vnetId: vnet.outputs.vnetId
    subnetName: 'compute-subnet'
  }
}
